const http = require('http');
const https = require('https');
const path = require('path');
const fs = require('fs');
const url = require('url');
const { VM } = require('vm2');

// ============================================================
// Secure Plugin Loader for API Gateway
// ============================================================

class PluginSandbox {
  constructor(options = {}) {
    this.timeout = options.timeout || 5000;
    this.allowedModules = new Set(options.allowedModules || []);
  }

  /**
   * Load and execute plugin code inside a sandboxed VM.
   * We NEVER use eval() or unsandboxed require() for user-supplied code.
   */
  loadPluginFromCode(code, pluginName) {
    const sandbox = {
      console: this._createSafeConsole(pluginName),
      setTimeout: undefined,
      setInterval: undefined,
      setImmediate: undefined,
      Buffer: undefined,
      process: undefined,
      __dirname: undefined,
      __filename: undefined,
      module: { exports: {} },
      exports: {},
    };

    const vm = new VM({
      timeout: this.timeout,
      sandbox,
      eval: false,
      wasm: false,
    });

    try {
      vm.run(code);
      const pluginExports = vm.run('module.exports');
      return this._validatePlugin(pluginExports, pluginName);
    } catch (err) {
      throw new Error(`Failed to load plugin "${pluginName}": ${err.message}`);
    }
  }

  /**
   * Load a plugin from a trusted file path (must be within allowed directory).
   */
  loadPluginFromFile(filePath, allowedDir) {
    const resolvedPath = path.resolve(filePath);
    const resolvedAllowedDir = path.resolve(allowedDir);

    // Path traversal protection
    if (!resolvedPath.startsWith(resolvedAllowedDir + path.sep)) {
      throw new Error(
        `Plugin path "${resolvedPath}" is outside allowed directory "${resolvedAllowedDir}"`
      );
    }

    // Only allow .js files
    if (path.extname(resolvedPath) !== '.js') {
      throw new Error(`Plugin file must have .js extension: ${resolvedPath}`);
    }

    // Check file exists
    if (!fs.existsSync(resolvedPath)) {
      throw new Error(`Plugin file not found: ${resolvedPath}`);
    }

    const code = fs.readFileSync(resolvedPath, 'utf-8');
    const pluginName = path.basename(resolvedPath, '.js');
    return this.loadPluginFromCode(code, pluginName);
  }

  _validatePlugin(pluginExports, pluginName) {
    if (!pluginExports || typeof pluginExports !== 'object') {
      throw new Error(`Plugin "${pluginName}" must export an object`);
    }

    const plugin = {
      name: pluginName,
      onRequest: null,
      onResponse: null,
      onError: null,
    };

    if (pluginExports.name && typeof pluginExports.name === 'string') {
      // Sanitize plugin name
      plugin.name = pluginExports.name.replace(/[^a-zA-Z0-9_-]/g, '');
    }

    if (typeof pluginExports.onRequest === 'function') {
      plugin.onRequest = pluginExports.onRequest;
    }

    if (typeof pluginExports.onResponse === 'function') {
      plugin.onResponse = pluginExports.onResponse;
    }

    if (typeof pluginExports.onError === 'function') {
      plugin.onError = pluginExports.onError;
    }

    if (!plugin.onRequest && !plugin.onResponse && !plugin.onError) {
      throw new Error(
        `Plugin "${pluginName}" must export at least one of: onRequest, onResponse, onError`
      );
    }

    return plugin;
  }

  _createSafeConsole(pluginName) {
    const prefix = `[plugin:${pluginName}]`;
    return {
      log: (...args) => console.log(prefix, ...args),
      warn: (...args) => console.warn(prefix, ...args),
      error: (...args) => console.error(prefix, ...args),
      info: (...args) => console.info(prefix, ...args),
    };
  }
}

// ============================================================
// Plugin Manager
// ============================================================

class PluginManager {
  constructor(options = {}) {
    this.plugins = [];
    this.sandbox = new PluginSandbox(options.sandbox || {});
    this.pluginDir = options.pluginDir
      ? path.resolve(options.pluginDir)
      : path.resolve(__dirname, 'plugins');
    this.maxPlugins = options.maxPlugins || 50;
    this.maxPluginSize = options.maxPluginSize || 100 * 1024; // 100KB
  }

  /**
   * Load plugins from a configuration object.
   */
  loadFromConfig(config) {
    if (!config || !Array.isArray(config.plugins)) {
      console.log('No plugins configured.');
      return;
    }

    for (const pluginConfig of config.plugins) {
      if (this.plugins.length >= this.maxPlugins) {
        console.warn(`Maximum plugin limit (${this.maxPlugins}) reached. Skipping remaining.`);
        break;
      }

      try {
        if (pluginConfig.file) {
          this._loadFilePlugin(pluginConfig);
        } else if (pluginConfig.code) {
          this._loadInlinePlugin(pluginConfig);
        } else {
          console.warn(`Plugin config missing "file" or "code": ${JSON.stringify(pluginConfig)}`);
        }
      } catch (err) {
        console.error(`Error loading plugin: ${err.message}`);
      }
    }
  }

  /**
   * Load plugins referenced by environment variable.
   * Env var should contain a path to a JSON config file (NOT raw code).
   */
  loadFromEnv(envVarName = 'GATEWAY_PLUGIN_CONFIG') {
    const configPath = process.env[envVarName];
    if (!configPath) {
      console.log(`No plugin config env var "${envVarName}" set.`);
      return;
    }

    const resolvedPath = path.resolve(configPath);

    // Ensure config file is a JSON file
    if (path.extname(resolvedPath) !== '.json') {
      throw new Error('Plugin config file must be a .json file');
    }

    if (!fs.existsSync(resolvedPath)) {
      throw new Error(`Plugin config file not found: ${resolvedPath}`);
    }

    const raw = fs.readFileSync(resolvedPath, 'utf-8');
    let config;
    try {
      config = JSON.parse(raw);
    } catch {
      throw new Error(`Invalid JSON in plugin config: ${resolvedPath}`);
    }

    this.loadFromConfig(config);
  }

  _loadFilePlugin(pluginConfig) {
    const plugin = this.sandbox.loadPluginFromFile(pluginConfig.file, this.pluginDir);
    plugin.priority = Number(pluginConfig.priority) || 0;
    plugin.enabled = pluginConfig.enabled !== false;
    this.plugins.push(plugin);
    this._sortPlugins();
    console.log(`Loaded file plugin: ${plugin.name} (priority: ${plugin.priority})`);
  }

  _loadInlinePlugin(pluginConfig) {
    const code = String(pluginConfig.code);

    if (code.length > this.maxPluginSize) {
      throw new Error(
        `Inline plugin code exceeds max size (${this.maxPluginSize} bytes)`
      );
    }

    const name = pluginConfig.name || `inline-${Date.now()}`;
    const plugin = this.sandbox.loadPluginFromCode(code, name);
    plugin.priority = Number(pluginConfig.priority) || 0;
    plugin.enabled = pluginConfig.enabled !== false;
    this.plugins.push(plugin);
    this._sortPlugins();
    console.log(`Loaded inline plugin: ${plugin.name} (priority: ${plugin.priority})`);
  }

  _sortPlugins() {
    this.plugins.sort((a, b) => b.priority - a.priority);
  }

  getEnabledPlugins() {
    return this.plugins.filter((p) => p.enabled);
  }
}

// ============================================================
// Request/Response Context (immutable-ish wrapper)
// ============================================================

class RequestContext {
  constructor(req) {
    const parsedUrl = url.parse(req.url, true);
    this.method = req.method;
    this.url = req.url;
    this.path = parsedUrl.pathname;
    this.query = { ...parsedUrl.query };
    this.headers = this._sanitizeHeaders({ ...req.headers });
    this.body = null;
    this.metadata = {};
    this._blocked = false;
    this._blockReason = '';
    this._blockStatus = 403;
    this._modifiedHeaders = {};
    this._modifiedPath = null;
  }

  _sanitizeHeaders(headers) {
    const sanitized = {};
    for (const [key, value] of Object.entries(headers)) {
      // Only include string headers, skip potentially dangerous ones from modification
      if (typeof value === 'string' || Array.isArray(value)) {
        sanitized[key.toLowerCase()] = value;
      }
    }
    return sanitized;
  }

  setHeader(name, value) {
    if (typeof name !== 'string' || typeof value !== 'string') return;
    const sanitizedName = name.toLowerCase().replace(/[^a-z0-9-]/g, '');
    // Prevent overriding critical headers
    const protectedHeaders = ['host', 'content-length', 'transfer-encoding'];
    if (protectedHeaders.includes(sanitizedName)) return;
    this._modifiedHeaders[sanitizedName] = value;
  }

  setPath(newPath) {
    if (typeof newPath !== 'string') return;
    // Basic path traversal protection
    const normalized = path.posix.normalize(newPath);
    if (normalized.includes('..')) return;
    this._modifiedPath = normalized;
  }

  block(reason, statusCode) {
    this._blocked = true;
    this._blockReason = typeof reason === 'string' ? reason.substring(0, 500) : 'Blocked by plugin';
    this._blockStatus = typeof statusCode === 'number' ? Math.min(Math.max(statusCode, 400), 599) : 403;
  }

  setMetadata(key, value) {
    if (typeof key !== 'string') return;
    // Limit metadata size
    const serialized = JSON.stringify(value);
    if (serialized && serialized.length < 10000) {
      this.metadata[key] = value;
    }
  }
}

class ResponseContext {
  constructor(statusCode, headers, body) {
    this.statusCode = statusCode;
    this.headers = { ...headers };
    this.body = body;
    this._modifiedHeaders = {};
    this._modifiedStatusCode = null;
    this._modifiedBody = null;
  }

  setHeader(name, value) {
    if (typeof name !== 'string' || typeof value !== 'string') return;
    const sanitizedName = name.toLowerCase().replace(/[^a-z0-9-]/g, '');
    this._modifiedHeaders[sanitizedName] = value;
  }

  setStatusCode(code) {
    if (typeof code === 'number' && code >= 100 && code <= 599) {
      this._modifiedStatusCode = code;
    }
  }

  setBody(body) {
    if (typeof body === 'string' || Buffer.isBuffer(body)) {
      this._modifiedBody = body;
    }
  }
}

// ============================================================
// API Gateway
// ============================================================

class APIGateway {
  constructor(options = {}) {
    this.port = options.port || 3000;
    this.targetHost = options.targetHost || 'localhost';
    this.targetPort = options.targetPort || 8080;
    this.targetProtocol = options.targetProtocol || 'http';
    this.requestTimeout = options.requestTimeout || 30000;
    this.maxBodySize = options.maxBodySize || 1024 * 1024; // 1MB

    this.pluginManager = new PluginManager({
      pluginDir: options.pluginDir,
      maxPlugins: options.maxPlugins,
      sandbox: options.sandbox,
    });

    this.server = null;
  }

  async _runPluginHook(hookName, context) {
    const plugins = this.pluginManager.getEnabledPlugins();

    for (const plugin of plugins) {
      if (typeof plugin[hookName] !== 'function') continue;

      try {
        // Run plugin hook with a timeout
        await Promise.race([
          Promise.resolve(plugin[hookName](context)),
          new Promise((_, reject) =>
            setTimeout(() => reject(new Error('Plugin timeout')), 5000)
          ),
        ]);
      } catch (err) {
        console.error(`Plugin "${plugin.name}" error in ${hookName}: ${err.message}`);
        // Continue to next plugin; don't let one plugin break the chain
      }

      // If request was blocked, stop processing
      if (hookName === 'onRequest' && context._blocked) {
        break;
      }
    }
  }

  _readBody(req) {
    return new Promise((resolve, reject) => {
      const chunks = [];
      let size = 0;

      req.on('data', (chunk) => {
        size += chunk.length;
        if (size > this.maxBodySize) {
          req.destroy();
          reject(new Error('Request body too large'));
          return;
        }
        chunks.push(chunk);
      });

      req.on('end', () => resolve(Buffer.concat(chunks)));
      req.on('error', reject);
    });
  }

  _proxyRequest(reqCtx, body) {
    return new Promise((resolve, reject) => {
      const targetPath = reqCtx._modifiedPath || reqCtx.path;
      const queryString = url.format({ query: reqCtx.query });
      const fullPath = queryString && queryString !== '?' ? targetPath + queryString : targetPath;

      const mergedHeaders = { ...reqCtx.headers, ...reqCtx._modifiedHeaders };
      // Update host header for the target
      mergedHeaders['host'] = this.targetHost + ':' + this.targetPort;

      const options = {
        hostname: this.targetHost,
        port: this.targetPort,
        path: fullPath,
        method: reqCtx.method,
        headers: mergedHeaders,
        timeout: this.requestTimeout,
      };

      const transport = this.targetProtocol === 'https' ? https : http;

      const proxyReq = transport.request(options, (proxyRes) => {
        const chunks = [];
        let size = 0;

        proxyRes.on('data', (chunk) => {
          size += chunk.length;
          if (size > this.maxBodySize * 10) {
            proxyRes.destroy();
            reject(new Error('Response body too large'));
            return;
          }
          chunks.push(chunk);
        });

        proxyRes.on('end', () => {
          resolve({
            statusCode: proxyRes.statusCode,
            headers: proxyRes.headers,
            body: Buffer.concat(chunks),
          });
        });

        proxyRes.on('error', reject);
      });

      proxyReq.on('error', reject);
      proxyReq.on('timeout', () => {
        proxyReq.destroy();
        reject(new Error('Proxy request timeout'));
      });

      if (body && body.length > 0) {
        proxyReq.write(body);
      }

      proxyReq.end();
    });
  }

  async _handleRequest(req, res) {
    const startTime = Date.now();

    try {
      // Read request body
      const body = await this._readBody(req);

      // Create request context
      const reqCtx = new RequestContext(req);
      reqCtx.body = body;

      // Run onRequest plugins
      await this._runPluginHook('onRequest', reqCtx);

      // Check if request was blocked by a plugin
      if (reqCtx._blocked) {
        res.writeHead(reqCtx._blockStatus, { 'content-type': 'application/json' });
        res.end(
          JSON.stringify({
            error: reqCtx._blockReason,
            status: reqCtx._blockStatus,
          })
        );
        console.log(
          `[${req.method}] ${req.url} -> BLOCKED (${reqCtx._blockStatus}) ${Date.now() - startTime}ms`
        );
        return;
      }

      // Proxy the request to the target
      const proxyResponse = await this._proxyRequest(reqCtx, body);

      // Create response context
      const resCtx = new ResponseContext(
        proxyResponse.statusCode,
        proxyResponse.headers,
        proxyResponse.body
      );

      // Run onResponse plugins
      await this._runPluginHook('onResponse', resCtx);

      // Build final response
      const finalStatusCode = resCtx._modifiedStatusCode || resCtx.statusCode;
      const finalHeaders = { ...resCtx.headers, ...resCtx._modifiedHeaders };
      const finalBody = resCtx._modifiedBody || resCtx.body;

      // Remove hop-by-hop headers
      const hopByHopHeaders = [
        'connection',
        'keep-alive',
        'proxy-authenticate',
        'proxy-authorization',
        'te',
        'trailer',
        'transfer-encoding',
        'upgrade',
      ];
      for (const h of hopByHopHeaders) {
        delete finalHeaders[h];
      }

      // Update content-length if body was modified
      if (resCtx._modifiedBody) {
        finalHeaders['content-length'] = Buffer.byteLength(finalBody);
      }

      res.writeHead(finalStatusCode, finalHeaders);
      res.end(finalBody);

      console.log(
        `[${req.method}] ${req.url} -> ${finalStatusCode} ${Date.now() - startTime}ms`
      );
    } catch (err) {
      console.error(`Gateway error: ${err.message}`);

      // Run onError plugins
      try {
        await this._runPluginHook('onError', {
          error: err.message,
          url: req.url,
          method: req.method,
        });
      } catch (pluginErr) {
        console.error(`Plugin onError hook failed: ${pluginErr.message}`);
      }

      if (!res.headersSent) {
        res.writeHead(502, { 'content-type': 'application/json' });
        res.end(
          JSON.stringify({
            error: 'Bad Gateway',
            message: 'The gateway encountered an error processing your request.',
          })
        );
      }
    }
  }

  loadPlugins(config) {
    this.pluginManager.loadFromConfig(config);
  }

  loadPluginsFromEnv(envVarName) {
    this.pluginManager.loadFromEnv(envVarName);
  }

  start() {
    this.server = http.createServer((req, res) => {
      this._handleRequest(req, res);
    });

    // Security: set timeouts
    this.server.timeout = this.requestTimeout;
    this.server.headersTimeout = 10000;
    this.server.keepAliveTimeout = 5000;
    this.server.maxHeadersCount = 100;

    this.server.listen(this.port, () => {
      console.log(`API Gateway listening on port ${this.port}`);
      console.log(
        `Proxying to ${this.targetProtocol}://${this.targetHost}:${this.targetPort}`
      );
      console.log(
        `Loaded ${this.pluginManager.getEnabledPlugins().length} plugin(s)`
      );
    });

    this.server.on('error', (err) => {
      console.error(`Server error: ${err.message}`);
    });

    return this.server;
  }

  stop() {
    if (this.server) {
      this.server.close(() => {
        console.log('API Gateway stopped.');
      });
    }
  }
}

// ============================================================
// Main Entry Point
// ============================================================

function main() {
  const gateway = new APIGateway({
    port: parseInt(process.env.GATEWAY_PORT, 10) || 3000,
    targetHost: process.env.TARGET_HOST || 'localhost',
    targetPort: parseInt(process.env.TARGET_PORT, 10) || 8080,
    targetProtocol: process.env.TARGET_PROTOCOL || 'http',
    pluginDir: process.env.PLUGIN_DIR || path.join(__dirname, 'plugins'),
    requestTimeout: parseInt(process.env.REQUEST_TIMEOUT, 10) || 30000,
    maxBodySize: parseInt(process.env.MAX_BODY_SIZE, 10) || 1024 * 1024,
    maxPlugins: parseInt(process.env.MAX_PLUGINS, 10) || 50,
    sandbox: {
      timeout: parseInt(process.env.PLUGIN_TIMEOUT, 10) || 5000,
    },
  });

  // Example: load plugins from a config file
  const configPath = process.env.GATEWAY_CONFIG || path.join(__dirname, 'gateway.config.json');
  if (fs.existsSync(configPath)) {
    try {
      const config = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      gateway.loadPlugins(config);
    } catch (err) {
      console.error(`Failed to load config: ${err.message}`);
    }
  }

  // Also try loading from env var
  try {
    gateway.loadPluginsFromEnv('GATEWAY_PLUGIN_CONFIG');
  } catch (err) {
    console.error(`Failed to load plugins from env: ${err.message}`);
  }

  gateway.start();

  // Graceful shutdown
  process.on('SIGTERM', () => {
    console.log('Received SIGTERM, shutting down...');
    gateway.stop();
    process.exit(0);
  });

  process.on('SIGINT', () => {
    console.log('Received SIGINT, shutting down...');
    gateway.stop();
    process.exit(0);
  });
}

main();

module.exports = { APIGateway, PluginManager, PluginSandbox, RequestContext, ResponseContext };